mapper.select:
select
  f.id, f.title, f.content, f.user_id, f.type, f.create_time,
  f.reply_content, f.reply_user_id, f.reply_time, f.status,
  coalesce(u.nick_name, u.user_name) as reply_user_name
from feedback f
left join user u on f.reply_user_id = u.id


        and f.id = #{id}


        and f.title like concat('%', #{title}, '%')


        and f.content = #{content}


        and f.user_id = #{userId}


        and f.type = #{type,typeHandler=com.caohao.config.EnumValueTypeHandler}


        and f.create_time = #{createTime}


        and f.reply_content = #{replyContent}


        and f.reply_user_id = #{replyUserId}


        and f.reply_time = #{replyTime}


        and f.status = #{status}


order by ifnull(f.reply_time, f.create_time) desc, f.create_time desc
